   236|/** Owner-facing description of each autonomy level. */
   237|export const APPROVAL_LEVELS: Record<ApprovalLevel, string> = {
   238|  1: 'Read-only analysis / report only.',
   239|  2: 'Create recommendations.',
   240|  3: 'Draft pull requests / migrations (nothing goes live).',
