   244|
   245|/** Returns the configured autonomy level for an agent. */
   246|export function getApprovalLevel(agentId: AgentId): ApprovalLevel {
   247|  return AGENTS[agentId]?.approvalLevel ?? 2;
   248|}
   249|
   250|const ALL_AGENT_IDS = Object.keys(AGENTS) as AgentId[];
   251|
   252|// ---------- In-process stores ----------
   253|
   254|const tasks = new Map<string, AgentTaskRecord>();
   255|const audit: AgentAuditEntry[] = [];
   256|const memory: AgentMemoryEntry[] = [];
   257|const handoffs: AgentHandoffRecord[] = [];
   258|
   259|const MAX_AUDIT = 500;
   260|const MAX_MEMORY = 500;
   261|const MAX_HANDOFFS = 500;
   262|
   263|// ---------- Durable persistence (Phase 1) ----------
   264|// The framework remains the runtime source of truth; this layer snapshots it to
   265|// disk after every mutation and rehydrates it on boot so tasks/audit/memory/
   266|// handoffs survive server restarts and deploys.
   267|
   268|let rehydrated = false;
   269|let snapshotTimer: ReturnType<typeof setTimeout> | null = null;
   270|
   271|function snapshotNow(): void {
   272|  void persistAgentState({
   273|    tasks: Array.from(tasks.values()),
   274|    audit,
   275|    memory,
   276|    handoffs,
   277|  });
   278|}
   279|
   280|/** Debounced snapshot so a burst of mutations writes once, not N times. */
   281|function scheduleSnapshot(): void {
   282|  if (!rehydrated) return;
   283|  if (snapshotTimer) return;
   284|  snapshotTimer = setTimeout(() => {
   285|    snapshotTimer = null;
   286|    snapshotNow();
   287|  }, 250);
   288|  if (typeof snapshotTimer === 'object' && typeof (snapshotTimer as { unref?: () => void }).unref === 'function') {
   289|    (snapshotTimer as { unref: () => void }).unref();
   290|  }
   291|}
   292|
   293|/** Rehydrate in-process state from the durable snapshot. Safe + idempotent. */
   294|export async function rehydrateAgentState(): Promise<{ rehydrated: boolean; tasks: number; audit: number; memory: number; handoffs: number }> {
   295|  const snapshot = await loadAgentState();
   296|  if (snapshot) {
   297|    for (const t of snapshot.tasks as AgentTaskRecord[]) {
   298|      if (t && typeof t.id === 'string' && !tasks.has(t.id)) tasks.set(t.id, t);
   299|    }
   300|    if (audit.length === 0 && snapshot.audit.length > 0) audit.push(...(snapshot.audit as AgentAuditEntry[]));
   301|    if (memory.length === 0 && snapshot.memory.length > 0) memory.push(...(snapshot.memory as AgentMemoryEntry[]));
   302|    if (handoffs.length === 0 && snapshot.handoffs.length > 0) handoffs.push(...(snapshot.handoffs as AgentHandoffRecord[]));
   303|  }
   304|  rehydrated = true;
   305|  return { rehydrated: Boolean(snapshot), tasks: tasks.size, audit: audit.length, memory: memory.length, handoffs: handoffs.length };
   306|}
   307|
   308|// Kick off rehydration once at module load; mark rehydrated even if it fails so
   309|// snapshots resume normally and a missing file never blocks the framework.
   310|void rehydrateAgentState().catch(() => {
   311|  rehydrated = true;
   312|});
   313|
   314|function nowIso(): string { return new Date().toISOString(); }
   315|function uid(prefix: string): string {
   316|  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
   317|    return `${prefix}_${crypto.randomUUID()}`;
   318|  }
   319|  return `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
   320|}
   321|
   322|function pushBounded<T>(arr: T[], item: T, max: number): void {
   323|  arr.push(item);
   324|  if (arr.length > max) arr.splice(0, arr.length - max);
   325|}
   326|
   327|// ---------- Audit ----------
   328|
   329|export function recordAudit(
   330|  agentId: AgentId,
   331|  action: string,
   332|  detail: string,
   333|  taskId: string | null = null,
   334|  metadata: Record<string, unknown> = {},
   335|): AgentAuditEntry {
   336|  const entry: AgentAuditEntry = {
   337|    id: uid('audit'),
   338|    agentId,
   339|    taskId,
   340|    action,
   341|    detail: detail.slice(0, 600),
   342|    metadata,
   343|    at: nowIso(),
   344|  };
   345|  pushBounded(audit, entry, MAX_AUDIT);
   346|  void appendAgentEvent({ type: 'audit', agentId, action, taskId, at: entry.at });
   347|  scheduleSnapshot();
   348|  return entry;
   349|}
   350|
   351|export function listAudit(limit: number = 100, agentId?: AgentId): AgentAuditEntry[] {
   352|  const filtered = agentId ? audit.filter((a) => a.agentId === agentId) : audit;
   353|  return filtered.slice(-Math.max(1, Math.min(500, limit))).reverse();
   354|}
   355|
   356|// ---------- Memory (namespaced) ----------
   357|
   358|export function writeAgentMemory(
   359|  agentId: AgentId,
   360|  key: string,
   361|  value: string,
   362|  metadata: Record<string, unknown> = {},
   363|): AgentMemoryEntry {
   364|  const def = AGENTS[agentId];
   365|  const entry: AgentMemoryEntry = {
   366|    id: uid('mem'),
   367|    agentId,
   368|    namespace: def.memoryNamespace,
   369|    key: key.slice(0, 120),
   370|    value: value.slice(0, 4000),
   371|    metadata,
   372|    at: nowIso(),
   373|  };
   374|  pushBounded(memory, entry, MAX_MEMORY);
   375|  recordAudit(agentId, 'memory.write', `key=${entry.key}`, null, { namespace: entry.namespace });
   376|  return entry;
   377|}
   378|
   379|export function readAgentMemory(agentId: AgentId, key?: string): AgentMemoryEntry[] {
   380|  const ns = AGENTS[agentId].memoryNamespace;
   381|  return memory
   382|    .filter((m) => m.namespace === ns && (key ? m.key === key : true))
   383|    .slice(-100)
   384|    .reverse();
   385|}
   386|
   387|// ---------- Risk policy ----------
   388|
   389|const RISK_RANK: Record<AgentRiskLevel, number> = { low: 0, medium: 1, high: 2 };
   390|
   391|export function classifyTaskRisk(goal: string): AgentRiskLevel {
   392|  const lower = goal.toLowerCase();
   393|  if (/(drop|delete|truncate|rollback|prod\b|production|wipe|destroy|migrate|force push|mainnet)/.test(lower)) {
   394|    return 'high';
   395|  }
   396|  if (/(deploy|patch|migration|release|publish|hotfix|env|secret)/.test(lower)) {
   397|    return 'medium';
   398|  }
   399|  return 'low';
   400|}
   401|
   402|export function isActionAllowed(agentId: AgentId, risk: AgentRiskLevel): { allowed: boolean; reason: string } {
   403|  const def = AGENTS[agentId];
   404|  if (RISK_RANK[risk] > RISK_RANK[def.riskLimit]) {
   405|    return {
   406|      allowed: false,
   407|      reason: `Risk ${risk} exceeds ${def.name} limit (${def.riskLimit}). Owner approval required.`,
   408|    };
   409|  }
   410|  return { allowed: true, reason: 'within risk limit' };
   411|}
   412|
   413|// ---------- Routing ----------
   414|
   415|export function routeTaskToAgent(goal: string): AgentId {
   416|  const lower = goal.toLowerCase();
   417|  let bestAgent: AgentId = 'operations';
   418|  let bestScore = 0;
   419|  for (const id of ALL_AGENT_IDS) {
   420|    if (id === 'cto_orchestrator') continue;
   421|    const def = AGENTS[id];
   422|    let score = 0;
   423|    for (const kw of def.routingKeywords) {
   424|      if (lower.includes(kw)) score += 1;
   425|    }
   426|    if (score > bestScore) {
   427|      bestScore = score;
   428|      bestAgent = id;
   429|    }
   430|  }
   431|  return bestAgent;
   432|}
   433|
   434|// ---------- Handoffs ----------
   435|
   436|export function recordHandoff(
   437|  fromAgent: AgentId,
   438|  toAgent: AgentId,
   439|  taskId: string,
   440|  reason: string,
   441|): AgentHandoffRecord {
   442|  const handoff: AgentHandoffRecord = {
   443|    id: uid('handoff'),
   444|    fromAgent,
   445|    toAgent,
   446|    taskId,
   447|    reason: reason.slice(0, 400),
   448|    at: nowIso(),
   449|  };
   450|  pushBounded(handoffs, handoff, MAX_HANDOFFS);
   451|  const task = tasks.get(taskId);
   452|  if (task) {
   453|    task.handoffs.push(handoff);
   454|    task.assignedAgent = toAgent;
   455|    task.updatedAt = handoff.at;
   456|  }
   457|  recordAudit(fromAgent, 'handoff.send', `to=${toAgent} reason=${reason}`, taskId);
   458|  recordAudit(toAgent, 'handoff.receive', `from=${fromAgent}`, taskId);
   459|  return handoff;
   460|}
   461|
   462|export function listHandoffs(limit: number = 100): AgentHandoffRecord[] {
   463|  return handoffs.slice(-Math.max(1, Math.min(500, limit))).reverse();
   464|}
   465|
   466|// ---------- Tasks ----------
   467|
   468|export type DispatchOptions = {
   469|  goal: string;
   470|  approverEmail?: string;
   471|  forceAgent?: AgentId;
   472|  metadata?: Record<string, unknown>;
   473|};
   474|
   475|export type DispatchResult = {
   476|  task: AgentTaskRecord;
   477|  audit: AgentAuditEntry[];
   478|};
   479|
   480|export function dispatchTask(opts: DispatchOptions): DispatchResult {
   481|  const goal = opts.goal.trim();
   482|  if (!goal) throw new Error('Task goal is required.');
   483|  const auditBatch: AgentAuditEntry[] = [];
   484|
   485|  const cto: AgentId = 'cto_orchestrator';
   486|  auditBatch.push(recordAudit(cto, 'task.received', `goal="${goal.slice(0, 120)}"`));
   487|
   488|  const routedAgent = opts.forceAgent ?? routeTaskToAgent(goal);
   489|  auditBatch.push(recordAudit(cto, 'task.routed', `to=${routedAgent}`));
   490|
   491|  const risk = classifyTaskRisk(goal);
   492|  const policy = isActionAllowed(routedAgent, risk);
   493|  const approvalRequired = !policy.allowed;
   494|  const isApproved = approvalRequired && Boolean(opts.approverEmail);
   495|
   496|  const taskId = uid('task');
   497|  const task: AgentTaskRecord = {
   498|    id: taskId,
   499|    goal,
   500|    assignedAgent: routedAgent,
   501|    status: 'pending',
   502|    risk,
   503|    approvalRequired,
   504|    approvedBy: isApproved ? (opts.approverEmail ?? null) : null,
   505|    approvedAt: isApproved ? nowIso() : null,
   506|    blockedReason: null,
   507|    result: null,
   508|    error: null,
   509|    handoffs: [],
   510|    steps: [],
   511|    createdAt: nowIso(),
   512|    updatedAt: nowIso(),
   513|  };
   514|
   515|  // Record the implicit handoff CTO -> specialist
   516|  const handoff = recordHandoff(cto, routedAgent, taskId, 'cto routing');
   517|  task.handoffs.push(handoff);
   518|
   519|  if (approvalRequired && !isApproved) {
   520|    task.status = 'blocked';
   521|    task.blockedReason = policy.reason;
   522|    task.steps.push({
   523|      agentId: routedAgent,
   524|      action: 'risk_gate',
   525|      status: 'blocked',
   526|      detail: policy.reason,
   527|      at: nowIso(),
   528|    });
   529|    auditBatch.push(recordAudit(routedAgent, 'task.blocked', policy.reason, taskId, { risk }));
   530|  } else {
   531|    task.status = 'running';
   532|    task.steps.push({
   533|      agentId: routedAgent,
   534|      action: 'analyze',
   535|      status: 'running',
   536|      detail: `Agent ${AGENTS[routedAgent].name} accepted task at risk=${risk}.`,
   537|      at: nowIso(),
   538|    });
   539|    auditBatch.push(recordAudit(routedAgent, 'task.accepted', `risk=${risk}`, taskId, isApproved ? { approvedBy: opts.approverEmail } : {}));
   540|  }
   541|
   542|  tasks.set(taskId, task);
   543|  return { task, audit: auditBatch };
   544|}
   545|
   546|export function completeTask(taskId: string, result: Record<string, unknown>): AgentTaskRecord {
   547|  const task = tasks.get(taskId);
   548|  if (!task) throw new Error(`Task ${taskId} not found.`);
   549|  task.status = 'completed';
   550|  task.result = result;
   551|  task.updatedAt = nowIso();
   552|  task.steps.push({
   553|    agentId: task.assignedAgent,
   554|    action: 'complete',
   555|    status: 'completed',
   556|    detail: 'Task completed successfully.',
   557|    at: task.updatedAt,
   558|  });
   559|  recordAudit(task.assignedAgent, 'task.completed', 'ok', taskId);
   560|  return task;
   561|}
   562|
   563|export function failTask(taskId: string, error: string): AgentTaskRecord {
   564|  const task = tasks.get(taskId);
   565|  if (!task) throw new Error(`Task ${taskId} not found.`);
   566|  task.status = 'failed';
