   109|/**
   110| * Trigger a rollback to the most recent successful previous deploy.
   111| * `force=true` bypasses the threshold check (used by the manual endpoint).
   112| */
   113|export async function triggerProductionRollback(input: { force?: boolean; reason?: string } = {}): Promise<RollbackResult> {
   114|  const force = input.force === true;
   115|  const reasonInput = (input.reason ?? '').trim() || 'Automated production guard rollback.';
   116|
   117|  if (rollbackInFlight) {
   118|    return { ok: false, triggered: false, reason: 'Rollback already in flight.', targetDeployId: null, newDeployId: null, incidentId: null };
   119|  }
   120|  const now = Date.now();
   121|  if (!force && now - lastRollbackAt < COOLDOWN_MS) {
   122|    return { ok: false, triggered: false, reason: 'Rollback cooldown active.', targetDeployId: null, newDeployId: null, incidentId: null };
   123|  }
   124|
   125|  if (!force) {
   126|    const health = getProductionHealth();
   127|    if (!health.thresholdExceeded) {
   128|      return { ok: false, triggered: false, reason: `Failure rate ${health.failureRate.toFixed(2)} below threshold.`, targetDeployId: null, newDeployId: null, incidentId: null };
   129|    }
   130|  }
   131|
   132|  rollbackInFlight = true;
   133|  try {
   134|    let deploys: RenderDeploy[];
   135|    try {
   136|      deploys = await fetchRenderDeploys();
   137|    } catch (error) {
   138|      const message = error instanceof Error ? error.message : String(error);
   139|      const incident = recordIncident({
   140|        source: 'rollback',
   141|        severity: 'critical',
   142|        message: `Production guard could not list deploys: ${message}`,
   143|        suggestedFix: 'Verify RENDER_API_KEY and RENDER_SERVICE_ID are set on the backend.',
   144|      });
   145|      return { ok: false, triggered: false, reason: message, targetDeployId: null, newDeployId: null, incidentId: incident.id };
   146|    }
   147|    const successful = deploys.filter((d) => (d.status ?? '').toLowerCase().includes('live') || (d.status ?? '').toLowerCase().includes('success'));
   148|    const previous = successful[1] ?? successful[0] ?? null;
   149|    if (!previous) {
   150|      const incident = recordIncident({
   151|        source: 'rollback',
   152|        severity: 'critical',
   153|        message: 'Production guard found no previous successful deploy to roll back to.',
   154|        suggestedFix: 'Manually investigate Render dashboard.',
   155|      });
   156|      return { ok: false, triggered: false, reason: 'No previous deploy available.', targetDeployId: null, newDeployId: null, incidentId: incident.id };
   157|    }
   158|
   159|    const result = await triggerRenderRollbackTo(previous.id);
   160|    lastRollbackAt = Date.now();
   161|    const incident = recordIncident({
   162|      source: 'rollback',
   163|      severity: 'critical',
   164|      message: result.ok
   165|        ? `Production guard rolled back to deploy ${previous.id}: ${reasonInput}`
   166|        : `Production guard rollback FAILED for deploy ${previous.id}: ${result.error ?? 'unknown error'}`,
   167|      suggestedFix: result.ok ? null : 'Investigate Render API logs and manually trigger rollback.',
   168|    });
   169|    return {
   170|      ok: result.ok,
   171|      triggered: result.ok,
   172|      reason: result.ok ? reasonInput : (result.error ?? 'rollback failed'),
   173|      targetDeployId: previous.id,
   174|      newDeployId: result.newDeployId,
   175|      incidentId: incident.id,
   176|    };
   177|  } finally {
   178|    rollbackInFlight = false;
   179|  }
